mapper.select:
SELECT SF.ID, SF.BUSINESS_TYPE, SF.FILE_BUCKET, SF.FILE_PATH, SF.FILE_SAVE_NAME, SF.FILE_NAME, SF.FILE_ICON, SF.CREATE_BY, SF.create_by_name, SF.CREATE_TIME, SF.UPDATE_BY, SF.update_BY_NAME, SF.UPDATE_TIME FROM SYS_FILE SF JOIN SYS_FILE_BUSINESS SFB ON SF.ID = SFB.FILE_ID
and SFB.FILE_ID = #{id}
and SF.BUSINESS_ID = #{businessId}
ORDER BY CREATE_TIME DESC
